import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { login } from '../api';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { loginUser } = useAuth();
  const navigate = useNavigate();

  const handle = e => setForm(f => ({ ...f, [e.target.name]: e.target.value }));

  const submit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await login(form);
      loginUser({ id: res.data.user_id, name: res.data.name, email: form.email }, res.data.access_token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.detail || 'Login failed. Please try again.');
    } finally { setLoading(false); }
  };

  return (
    <div style={styles.page}>
      <div style={styles.left}>
        <div style={styles.leftContent}>
          <div style={styles.logo}>🌱 MindEase</div>
          <h1 style={styles.headline}>Your mental wellness companion</h1>
          <p style={styles.sub}>A safe space to talk, track your mood, and understand your mental health — built for college students.</p>
          <div style={styles.features}>
            {['💬 AI-powered emotional support','📊 Daily mood tracking','📋 Mental health self-assessments','🔒 Secure & private'].map(f => (
              <div key={f} style={styles.featureItem}>{f}</div>
            ))}
          </div>
        </div>
      </div>
      <div style={styles.right}>
        <div style={styles.formCard}>
          <h2 style={styles.formTitle}>Welcome back</h2>
          <p style={styles.formSub}>Sign in to continue your journey</p>
          {error && <div style={styles.errorBox}>{error}</div>}
          <form onSubmit={submit} style={styles.form}>
            <div style={styles.field}>
              <label style={styles.label}>Email</label>
              <input name="email" type="email" required value={form.email} onChange={handle}
                className="input-field" placeholder="you@college.edu" />
            </div>
            <div style={styles.field}>
              <label style={styles.label}>Password</label>
              <input name="password" type="password" required value={form.password} onChange={handle}
                className="input-field" placeholder="••••••••" />
            </div>
            <button type="submit" className="btn-primary" style={styles.submitBtn} disabled={loading}>
              {loading ? 'Signing in…' : 'Sign in →'}
            </button>
          </form>
          <p style={styles.switchLink}>
            New here? <Link to="/register" style={styles.link}>Create an account</Link>
          </p>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: { display: 'flex', minHeight: '100vh' },
  left: {
    flex: 1, background: 'linear-gradient(145deg, var(--teal-dark) 0%, var(--sage) 100%)',
    display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 48,
  },
  leftContent: { maxWidth: 440, color: 'white' },
  logo: { fontFamily: 'var(--font-serif)', fontSize: '1.6rem', marginBottom: 32, opacity: 0.9 },
  headline: { fontSize: '2.8rem', marginBottom: 16, lineHeight: 1.15, color: 'white' },
  sub: { fontSize: '1.05rem', opacity: 0.85, marginBottom: 36, lineHeight: 1.6 },
  features: { display: 'flex', flexDirection: 'column', gap: 12 },
  featureItem: { fontSize: '0.95rem', opacity: 0.9, display: 'flex', alignItems: 'center', gap: 8 },
  right: { width: 460, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 40, background: 'var(--surface)' },
  formCard: { width: '100%', maxWidth: 380 },
  formTitle: { fontSize: '2rem', marginBottom: 6, color: 'var(--ink)' },
  formSub: { color: 'var(--mist)', marginBottom: 28 },
  errorBox: { background: 'var(--rose-pale)', border: '1px solid var(--rose)', color: '#b03a4a', padding: '10px 14px', borderRadius: 'var(--radius-sm)', marginBottom: 16, fontSize: '0.9rem' },
  form: { display: 'flex', flexDirection: 'column', gap: 18 },
  field: { display: 'flex', flexDirection: 'column', gap: 6 },
  label: { fontSize: '0.85rem', fontWeight: 600, color: 'var(--ink-light)' },
  submitBtn: { width: '100%', marginTop: 8, padding: '14px' },
  switchLink: { textAlign: 'center', marginTop: 20, fontSize: '0.9rem', color: 'var(--mist)' },
  link: { color: 'var(--teal)', fontWeight: 600 },
};
